#include <stdio.h>
#include <stdlib.h>

int lower_bound(int *arr, int size, int key) {
    int l = 0, r = size; // [l, r)
    while (l < r) {
        int m = l + (r - l) / 2;
        if (arr[m] < key) l = m + 1;
        else r = m;
    }
    return l;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int *tails = (int*)malloc(N * sizeof(int));
        int len = 0;
        for (int i = 0; i < N; ++i) {
            int pos = lower_bound(tails, len, a[i]);
            if (pos == len) {
                tails[len++] = a[i];
            } else {
                tails[pos] = a[i];
            }
        }
        printf("%d\n", N - len);
        free(a);
        free(tails);
    }
    return 0;
}

