import sys, bisect

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        a = [next(it) for _ in range(N)]
        tails = []
        for x in a:
            pos = bisect.bisect_left(tails, x)
            if pos == len(tails):
                tails.append(x)
            else:
                tails[pos] = x
        out_lines.append(str(N - len(tails)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

