const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = input[idx++];
  const a = input.slice(idx, idx + N);
  idx += N;
  const tails = [];
  for (const x of a) {
    // binary search lower bound
    let l = 0, r = tails.length;
    while (l < r) {
      const m = (l + r) >> 1;
      if (tails[m] < x) l = m + 1; else r = m;
    }
    if (l === tails.length) tails.push(x);
    else tails[l] = x;
  }
  outputs.push(String(N - tails.length));
}
